using ChatGPTImageOrchestrator.Application.Common.Interfaces; namespace ChatGPTImageOrchestrator.Web.BackgroundServices; public class ImageGenerationWorker(IServiceProvider sp, IBackgroundTaskQueue queue, ILogger<ImageGenerationWorker> logger):BackgroundService{ protected override async Task ExecuteAsync(CancellationToken stoppingToken){ while(!stoppingToken.IsCancellationRequested){ var _=await queue.DequeueAsync(stoppingToken); using var scope=sp.CreateScope(); logger.LogInformation("Dequeued project for processing"); } } }
